  ('retired-7ec62a85-moex-00213', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'essay', '內政部就某警察特考三等考試錄取人員請求安排至警察大學接受訓練
之請求，先函覆其除經免除教育訓練人員外，均在警察專科學校接受訓
練等語。後來，內政部又另就該警察特考錄取人員申請之同一事件，重
新審查，並再函文載明「查台端業已完成警察特考錄取人員訓練，其受
訓權已獲滿足，自毋需再接受訓練。」等語。試問前、後函文的內容法
律性質為何？並申論其理由。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00214', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'essay', '甲主張其所有之建物遭執行機關違法拆除，執行機關應負國家賠償責
任，惟未提起行政救濟而逕提起國家賠償訴訟。反之，執行機關否認有
何違法情事且主張甲就行政處分是否無效或違法，應先依行政爭訟程序
確定之，以此置辯。試問：甲未先提起行政救濟，是否得選擇逕行向民
事法院請求國家賠償？並申論其理由。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00215', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於行政法法源之敘述，下列何者錯誤？ 施行慣例不能作為限制人民自由之處分依據 如非與當時有效施行之成文法明文違背，行政先例得為行政措施之依據 行政機關處理某類事物反覆之慣行，不生拘束行政機關之效力 習慣法之成立要件需要具備主觀上法之確信', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00216', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '如行政機關對因流行性傳染病致經營遇困境之廠商提供無息紓困貸款，下列敘述何者正確？ 廠商如因未獲貸款而發生爭議，應向普通法院提起訴訟 因為國家財政有限，行政機關得自行決定提供紓困貸款之對象 行政機關對於提供紓困貸款之對象，無正當理由不得為差別待遇 行政機關於拒絕貸款前，應適用行政程序法給予廠商陳述意見機會 13730', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00217', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '臺北市樹木保護自治條例為保護市內老樹與維護生態而制定，並且規定有罰則，依地方制度法第 26條規定，該自治條例的特點： 無須定以自治團體名稱  得處以拘役 必須先經過中央目的主管機關核定  罰鍰得超過新臺幣10萬元', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00218', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '「集會遊行之不予許可、限制或命令解散，應公平合理考量人民集會、遊行權利與其他法益間之 均衡維護，以適當之方法為之，不得逾越所欲達成目的之必要限度。」上述規定為下列何種原則 之具體展現？ 法律優位原則  比例原則  授權明確性原則  信賴保護原則', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00219', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '依我國現行法規定，下列何者非屬公法人？ 直轄市山地原住民區   國家運動訓練中心 國家圖書館    國家表演藝術中心', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00220', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '屏東縣政府將原住民慶典活動委由該縣牡丹鄉辦理，此種情形屬於下列何者？ 權限委任  權限委託  委辦  職務協助', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00221', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '依據現行有關規定及實務見解，關於公務人員之考績權之敘述，下列何者錯誤？ 公務人員年終考績被列為丙等者，由於未改變其身分不得提起行政訴訟 公務人員年終考績被列為丙等者，將影響其陞任之權利 公務人員年終考績被列為丙等者，將影響其參加升官等訓練之權益 公務人員之考績評定，學理上認為是高度屬人性判斷之事項', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00222', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於公務員懲戒法制之敘述，下列何者正確？ 行政院部會首長認為其所屬薦任第十職等之公務員有違法執行職務情事，得將該公務員逕送懲 戒法院審理 公務員懲戒處分之種類包括停職 經監察院移送懲戒法院審理中之公務員，於懲戒法院審理確定前，仍得申請退休 公務員因懲戒法庭裁定停止其職務，其於停職期間所為之職務行為，不生效力', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "f48eb494fa0a", "answer_pdf_sha1": "ed039c4bff7b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL)
